package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Reader;
import java.io.Serializable;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void format_withNormalValues_returnsFormattedString() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void format_withNullValue_returnsFormattedString() throws IOException {
        String result = csvFormat.format("a", null, "c");
        assertEquals("a,,c", result);
    }

    @Test
    void format_withEmptyValues_returnsEmptyString() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void format_whenCSVPrinterThrowsIOException_throwsIllegalStateException() throws Exception {
        // Create a proxy for CSVPrinter that throws IOException on printRecord
        Class<?> csvPrinterClass = CSVPrinter.class;

        Constructor<?> ctor = csvPrinterClass.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        ctor.setAccessible(true);

        CSVPrinter proxy = (CSVPrinter) Proxy.newProxyInstance(
                csvPrinterClass.getClassLoader(),
                new Class<?>[] { csvPrinterClass },
                new InvocationHandler() {
                    @Override
                    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                        if ("printRecord".equals(method.getName())) {
                            throw new IOException("io error");
                        }
                        if ("close".equals(method.getName()) || "flush".equals(method.getName())) {
                            return null;
                        }
                        // For other methods, call the real constructor and delegate
                        return method.invoke(ctor.newInstance(new StringWriter(), csvFormat), args);
                    }
                });

        // Use reflection to replace CSVFormat.format's CSVPrinter creation temporarily
        // Since CSVFormat.format creates new CSVPrinter(out, this) directly,
        // we use a subclass of CSVFormat that overrides format to use our proxy.

        CSVFormat csvFormatMock = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeaderComments(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getIgnoreHeaderCase()) {

            @Override
            public String format(final Object... values) {
                final StringWriter out = new StringWriter();
                try {
                    // Instead of new CSVPrinter, use our proxy that throws IOException
                    CSVPrinter printer = proxy;
                    printer.printRecord(values);
                    return out.toString().trim();
                } catch (final IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            csvFormatMock.format("a", "b");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("io error", thrown.getCause().getMessage());
    }
}
